'use client';

import { useState } from 'react';
import {
  AccountPanel,
  AppearancePanel,
  NotificationsPanel,
  ProfileDetailsPanel,
} from './panels';
import { ProfileViewShell } from '../../components/profile/ProfileViewShell';
import {
  activeMockUser,
  canView,
  mockProfileAchievements,
  mockProfileForm,
  siteContent,
} from '../../mocks';

export default function ProfilePage() {
  const [tab, setTab] = useState<
    'profile' | 'notifications' | 'appearance' | 'account'
  >('profile');
  const [saved, setSaved] = useState(false);
  const [form, setForm] = useState({ ...mockProfileForm });
  const [notifications, setNotifications] = useState({
    lessonReminder: true,
    streakAlert: true,
    weeklyReport: true,
    newVocab: false,
    teacherMessages: true,
  });
  const [theme, setTheme] = useState<'light' | 'dark' | 'auto'>('light');

  if (!canView('profile', activeMockUser.role)) return null;

  return (
    <ProfileViewShell
      title={siteContent.profile.title}
      subtitle={`${siteContent.profile.subtitle} · ${activeMockUser.role}`}
      avatar={activeMockUser.avatarInitials}
      name={form.name}
      meta={`${activeMockUser.targetLevel} · ${activeMockUser.role}`}
      badges={[
        { label: 'Upper-Intermediate' },
        { label: 'Active learner', variant: 'green' },
      ]}
      stats={[
        { value: '847', label: 'Words' },
        { value: '38', label: 'Lessons' },
        { value: '14', label: 'Streak' },
      ]}
      achievements={mockProfileAchievements}
      tab={tab}
      onTabChange={setTab}
      tabs={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <ProfileDetailsPanel
                form={form}
                setForm={setForm}
                saved={saved}
                onSave={() => {
                  setSaved(true);
                  setTimeout(() => setSaved(false), 2500);
                }}
              />
            ),
          },
          {
            value: 'notifications',
            label: 'Notifications',
            panel: (
              <NotificationsPanel
                notifications={notifications}
                setNotifications={setNotifications}
              />
            ),
          },
          {
            value: 'appearance',
            label: 'Appearance',
            panel: <AppearancePanel theme={theme} setTheme={setTheme} />,
          },
          {
            value: 'account',
            label: 'Account',
            panel: <AccountPanel />,
          },
      ]}
    />
  );
}
